<template>
  <div v-if="categories.length" class="category-nav"><section v-for="(section, idx) in categories" :key="section.id" class="category-section"><div class="category-index">{{ String(idx + 1).padStart(2, '0') }}</div><div class="category-content"><div class="category-header"><span class="category-main"><span class="category-icon" :style="{ color: iconColor(idx) }">{{ section.name.charAt(0) }}</span><span>{{ section.name }}</span></span><router-link :to="{ path: '/resources', query: { categoryId: section.id } }" class="category-more">查看全部 <span>&rarr;</span></router-link></div><div v-if="section.children && section.children.length" class="category-children"><router-link v-for="child in section.children" :key="child.id" :to="{ path: '/resources', query: { categoryId: child.id } }" class="category-child">{{ child.name }}</router-link></div></div></section></div>
  <div v-else-if="loading" class="category-loading"><n-skeleton text :repeat="3" /></div>
</template>
<script setup>
import { ref, onMounted } from 'vue'; import { getCategoryTree } from '@/api/category'
const categories = ref([]); const loading = ref(true); const iconColors = ['#0f6d70','#b36e26','#597b55','#9c5d45','#596d84']; function iconColor(idx) { return iconColors[idx % iconColors.length] }
onMounted(async () => { try { const res = await getCategoryTree(); categories.value = res.data || [] } catch {} finally { loading.value = false } })
</script>
